    id uuid DEFAULT gen_random_uuid() NOT NULL,
    account_id uuid NOT NULL,
    path character varying(1024) NOT NULL,
    parent_path character varying(1024) NOT NULL,
    name character varying(255) NOT NULL,
    type character varying(10) NOT NULL,
    storage_key character varying(64),
    size_bytes bigint DEFAULT 0 NOT NULL,
    content_type character varying(128),
    track_id character varying(12),
    access_count integer DEFAULT 0 NOT NULL,
    last_accessed_at timestamp with time zone,
    deleted boolean DEFAULT false NOT NULL,
    permissions character varying(10) DEFAULT 'rwxr-xr-x'::character varying,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    created_by character varying(100),
    updated_by character varying(100),
    version integer DEFAULT 0 NOT NULL,
    inline_content bytea,
    storage_bucket character varying(10) DEFAULT 'STANDARD'::character varying,
    compressed boolean DEFAULT false NOT NULL,
    CONSTRAINT virtual_entries_type_check CHECK (((type)::text = ANY ((ARRAY['DIR'::character varying, 'FILE'::character varying])::text[])))
);


ALTER TABLE public.virtual_entries OWNER TO postgres;

--
-- Name: TABLE virtual_entries; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON TABLE public.virtual_entries IS 'Phantom Folder virtual filesystem. Folders are zero-cost DB rows. Files reference CAS via storage_key.';


--
-- Name: COLUMN virtual_entries.parent_path; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.virtual_entries.parent_path IS 'Immediate parent directory path. Enables O(1) directory listings via index.';


--
-- Name: COLUMN virtual_entries.storage_key; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.virtual_entries.storage_key IS 'SHA-256 hash pointing to content-addressed storage. NULL for DIR entries.';


--
-- Name: COLUMN virtual_entries.compressed; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.virtual_entries.compressed IS 'Whether inline_content is gzip-compressed. False for legacy uncompressed rows.';


--
-- Name: webhook_connectors; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.webhook_connectors (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name character varying(255) NOT NULL,
    type character varying(30),
    url character varying(1024),
    auth_token character varying(512),
    username character varying(255),
    password character varying(255),
    min_severity character varying(20),
    snow_instance_id character varying(255),
    snow_assignment_group character varying(255),
    snow_category character varying(100),
    active boolean DEFAULT true NOT NULL,
    last_triggered timestamp with time zone,
    total_notifications integer DEFAULT 0 NOT NULL,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp without time zone,
    created_by character varying(100),
    updated_by character varying(100),
    trigger_events jsonb,
    custom_headers jsonb
);


ALTER TABLE public.webhook_connectors OWNER TO postgres;

